/**
 * This Code node will:
 * 1. Gather all file paths from the incoming items (assuming each item has `item.json.filePath`).
 * 2. Build a single text string, each line in FFmpeg concat format: `file '/path/to/audio.mp3'`
 * 3. Convert that text to binary (Base64) so the next node ("Write Binary File") can save it as `concat_list.txt`.
 */

const items = $input.all();

// Build the concat list
let concatListText = '';

items.forEach(item => {
  // The 'Save File' node outputs the path in item.json.filePath
  const filePath = item.json.filePath;
  if (filePath) {
    concatListText += `file '${filePath}'\n`;
  }
});

// The 'Save concat_list' node expects binary data
const buffer = Buffer.from(concatListText, 'utf-8');
const base64Data = buffer.toString('base64');

return [
  {
    json: {},
    binary: {
      data: {
        data: base64Data,
        mimeType: 'text/plain',
        fileName: 'concat_list.txt'
      }
    }
  }
];

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

// Define the temporary directory path
const tempDir = '/tmp/dailydigest';
const concatListPath = path.join(tempDir, 'concat_list.txt');
const finalMergedPath = path.join(tempDir, 'final_merged.mp3');

try {
  // 1. Create temp directory if it doesn't exist
  if (!fs.existsSync(tempDir)) {
    fs.mkdirSync(tempDir, { recursive: true });
    console.log(`Created temp directory: ${tempDir}`);
  } else {
    console.log(`Temp directory already exists: ${tempDir}`);
  }

  // 2. Check if concat list file exists
  if (!fs.existsSync(concatListPath)) {
    throw new Error(`Concat list file not found: ${concatListPath}`);
  }

  // 3. Execute FFmpeg command to merge audio files
  console.log('Starting FFmpeg merge process...');
  const ffmpegCommand = `ffmpeg -f concat -safe 0 -i "${concatListPath}" -c copy "${finalMergedPath}" -y`;

  execSync(ffmpegCommand, { stdio: 'inherit' });
  console.log(`Audio files merged successfully: ${finalMergedPath}`);

  // 4. Verify the merged file was created
  if (!fs.existsSync(finalMergedPath)) {
    throw new Error('Failed to create merged audio file');
  }

  // 5. Clean up temporary files (but keep the final merged file)
  console.log('Cleaning up temporary files...');

  // Remove all individual audio chunk files
  const cleanupCommand = `find "${tempDir}" -name "dailydigest_*.mp3" -type f -delete`;
  execSync(cleanupCommand);

  // Remove the concat list file
  if (fs.existsSync(concatListPath)) {
    fs.unlinkSync(concatListPath);
    console.log('Removed concat list file');
  }

  console.log('Cleanup completed successfully');

  // 6. Return the path to the final merged MP3 file
  return [{
    json: {
      finalMergedPath: finalMergedPath,
      success: true,
      message: 'Audio files merged and temporary files cleaned up successfully'
    }
  }];

} catch (error) {
  console.error('Error in merge and cleanup process:', error.message);

  // Return error information
  return [{
    json: {
      success: false,
      error: error.message,
      finalMergedPath: null
    }
  }];
}

