const execId = `exec_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
const data = $input.item.json;
const title = data.fields['Title EN'] || data.fields['Title HE'] || '';
const outline = data.fields['Outline'] || '';
const postType = data.fields['Type'] || '';
const status = data.fields['Status'] || '';
const language = data.fields['Language'] || 'en';
const keywords = data.fields['Keywords'] || '';
const slugRaw = data.fields['Slug EN'] || data.fields['Slug HE'] || title;
const slug = (slugRaw || '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '');

// Smart validation with caching logic
const tooShort = outline.trim().length < 100 || title.trim().length < 10;
const missingType = !postType || postType === '';
const notApproved = status !== 'Approved';
const notPostType = postType !== 'blog_post' && postType !== 'service' && postType !== 'faq' && postType !== 'glossary' && postType !== 'case_study';

// Check if already processed (basic caching) - WP_Posts is a linked record field
const alreadyProcessed = data.fields['WP_Posts'] && data.fields['WP_Posts'].length > 0;

// Smart model selection based on content complexity (using outline length as proxy)
const outlineLength = outline.length;
let selectedModel = 'claude-3-5-sonnet-20241022';
if (outlineLength > 2000) {
  selectedModel = 'claude-3-5-sonnet-20241022';
} else if (outlineLength < 800) {
  selectedModel = 'claude-3-haiku-20240307';
}

// Cost estimation
const costEstimate = selectedModel.includes('sonnet') ? 0.15 : 0.05;

const shouldProcess = !tooShort && !missingType && !notApproved && !notPostType && !alreadyProcessed;

return {
  json: {
    ...data,
    execId,
    title,
    outline,
    postType,
    status,
    language,
    keywords,
    slug,
    selectedModel,
    costEstimate,
    shouldProcess,
    validationErrors: {
      tooShort,
      missingType,
      notApproved,
      notPostType,
      alreadyProcessed
    }
  }
};

