// Convert Markdown to Gutenberg blocks
function convertToGutenberg(markdown) {
  let blocks = [];
  const lines = markdown.split('\n');

  lines.forEach(line => {
    if (line.startsWith('# ')) {
      blocks.push(`<!-- wp:heading {\"level\":1} -->\n<h1>${line.replace('# ', '')}</h1>\n<!-- /wp:heading -->`);
    } else if (line.startsWith('## ')) {
      blocks.push(`<!-- wp:heading {\"level\":2} -->\n<h2>${line.replace('## ', '')}</h2>\n<!-- /wp:heading -->`);
    } else if (line.startsWith('### ')) {
      blocks.push(`<!-- wp:heading {\"level\":3} -->\n<h3>${line.replace('### ', '')}</h3>\n<!-- /wp:heading -->`);
    } else if (line.startsWith('- ')) {
      blocks.push(`<!-- wp:list -->\n<ul><li>${line.replace('- ', '')}</li></ul>\n<!-- /wp:list -->`);
    } else if (line.trim()) {
      blocks.push(`<!-- wp:paragraph -->\n<p>${line}</p>\n<!-- /wp:paragraph -->`);
    }
  });

  return blocks.join('\n\n');
}

const gutenbergContent = convertToGutenberg(content);
const slug = d.title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '');

return {
  json: {
    ...d,
    wpContent: gutenbergContent,
    wpTitle: d.title,
    wpSlug: slug,
    wpExcerpt: content.substring(0, 155) + '...'
  }
};

